// Simple footer shown on every page
import "./Footer.css";

function Footer() {
  return (
    <footer className="footer">
      <div className="container footer-content">
        <p>
          Cine<span>Scope</span> &copy; {new Date().getFullYear()} — built as
          a college project.
        </p>
        <p className="footer-credit">Movie data provided by the OMDb API</p>
      </div>
    </footer>
  );
}

export default Footer;
